input.old_string:
case "${1:-deploy}" in
  sync) cmd_sync ;;
  deploy) cmd_deploy ;;
  open-sg) cmd_open_sg ;;
  status) load_state; cmd_status ;;
  worker-logs) cmd_worker_logs "$@" ;;
  *) die "Usage: $0 {sync|deploy|open-sg|status|worker-logs}" ;;
esac

input.new_string:
case "${1:-deploy}" in
  sync) cmd_sync ;;
  deploy) cmd_deploy ;;
  prune) cmd_prune ;;
  open-sg) cmd_open_sg ;;
  status) load_state; cmd_status ;;
  worker-logs) cmd_worker_logs "$@" ;;
  *) die "Usage: $0 {sync|deploy|prune|open-sg|status|worker-logs}" ;;
esac
